mapper.select:
SELECT id, user_id, period, selected_gym_id, status, source, metrics::text AS metrics, grade::text AS grade, tip::text AS tip, next_month_goal::text AS next_month_goal, recommended_gyms::text AS recommended_gyms, narrative::text AS narrative, requirement::text AS requirement, model, prompt_version, generated_at, created_at, updated_at FROM monthly_reports WHERE user_id = #{userId} AND period = #{period}
AND selected_gym_id IS NULL
AND selected_gym_id = #{gymId}

SELECT g.id AS gym_id, g.name, COUNT(DISTINCT v.id)::int AS matching_video_count, COALESCE(jsonb_agg(DISTINCT t.technique ORDER BY t.technique), '[]'::jsonb)::text AS matched_techniques FROM gyms g JOIN videos v ON v.gym_id = g.id JOIN analysis_video_results r ON r.video_id = v.id CROSS JOIN LATERAL jsonb_array_elements_text( COALESCE(r.final_techniques, '[]'::jsonb) ) AS t(technique) WHERE g.status = 'active' AND g.deleted_at IS NULL AND v.deleted_at IS NULL AND v.is_public = TRUE AND v.status = 'done'
AND t.technique IN
#{technique}
AND FALSE
GROUP BY g.id, g.name ORDER BY matching_video_count DESC, g.id ASC LIMIT #{size}
